        if n == 0:
            return 1
        if n == 1:
            return 1
        return 0
    if p % 2 == 0:
        return modp(n % 2, p % 2) * 2 ** (n // 2)
    else:
        return modp(n % 2, p % 2) * 2 ** (n // 2) * 2 % p

