def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    if number > 1000:
        raise ValueError("Number is greater than 1000!")
    else:
        num_to_roman = { 1: "i", 2: "ii", 3: "iii", 4: "iv", 5: "v", 6: "vi", 7: "vii", 8: "viii", 9: "ix", 10: "x", 20: "xx", 30: "xxx", 40: "xl", 50: "l", 60: "lx", 70: "lxx", 80: "lxxx", 90: "xc", 100: "c", 200: "cc", 300: "ccc", 400: "cd", 500: "d", 600: "dc", 700: "dcc", 800: "dccc", 900: "cm", 1000: "m" }
    result = []
    for n, r in num_to_roman.items():
        count, num = divmod(number, n)
        result.append(r * count)
        number -= count * n
    return ''.join(result)

